import java.util.*;

public class Solution {
    public static long solve(long[][] points) {
        int n = points.length;
        long res = 0;

        for (int i = 0; i < n; ++i) {
            Map<Pair, Set<Pair>> slopeMap = new HashMap<>();
            for (int j = 0; j < n; ++j) {
                if (i == j) continue;
                long dx = points[j][0] - points[i][0];
                long dy = points[j][1] - points[i][1];
                if (dx == 0 && dy == 0) continue;

                long g = gcd(dx, dy);
                if (g != 0) {
                    dx /= g;
                    dy /= g;
                }
                if (dx < 0 || (dx == 0 && dy < 0)) {
                    dx = -dx;
                    dy = -dy;
                }
                Pair key = new Pair(dx, dy);
                slopeMap.computeIfAbsent(key, k -> new HashSet<>()).add(new Pair(points[j][0], points[j][1]));
            }

            for (Map.Entry<Pair, Set<Pair>> entry : slopeMap.entrySet()) {
                int cnt = entry.getValue().size();
                if (cnt >= 3) {
                    res += cnt * (cnt - 1) * (cnt - 2) / 6;
                }
            }
        }

        Map<Line, Long> lineCount = new HashMap<>();
        for (int i = 0; i < n; ++i) {
            for (int j = i + 1; j < n; ++j) {
                long x1 = points[i][0], y1 = points[i][1];
                long x2 = points[j][0], y2 = points[j][1];

                long A = y2 - y1;
                long B = x1 - x2;
                long C = x2 * y1 - x1 * y2;

                long g = gcd(gcd(A, B), C);
                if (g != 0) {
                    A /= g;
                    B /= g;
                    C /= g;
                }
                if (A < 0 || (A == 0 && B < 0)) {
                    A = -A;
                    B = -B;
                    C = -C;
                }
                Line line = new Line(A, B, C);
                lineCount.put(line, lineCount.getOrDefault(line, 0L) + 1);
            }
        }

        long total = 0;
        for (long cnt : lineCount.values()) {
            if (cnt >= 4) {
                total += cnt * (cnt - 1) * (cnt - 2) * (cnt - 3) / 24;
            }
        }

        res -= total * 4;

        return res;
    }

    private static long gcd(long a, long b) {
        return b == 0 ? a : gcd(b, a % b);
    }

    static class Pair {
        long first, second;

        Pair(long first, long second) {
            this.first = first;
            this.second = second;
        }

        @Override
        public boolean equals(Object o) {
            if (this == o) return true;
            if (o == null || getClass() != o.getClass()) return false;
            Pair pair = (Pair) o;
            return first == pair.first && second == pair.second;
        }

        @Override
        public int hashCode() {
            return Objects.hash(first, second);
        }
    }

    static class Line {
        long A, B, C;

        Line(long A, long B, long C) {
            this.A = A;
            this.B = B;
            this.C = C;
        }

        @Override
        public boolean equals(Object o) {
            if (this == o) return true;
            if (o == null || getClass() != o.getClass()) return false;
            Line line = (Line) o;
            return A == line.A && B == line.B && C == line.C;
        }

        @Override
        public int hashCode() {
            return Objects.hash(A, B, C);
        }
    }
}
