#include <map>
#include <set>
#include <utility>
#include <algorithm>

using namespace std;

long long solve(std::vector<std::vector<long long>> points) {
    int n = points.size();
    long long res = 0;

    for (int i = 0; i < n; ++i) {
        map<pair<long long, long long>, set<pair<long long, long long>>> slopeMap;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            long long dx = points[j][0] - points[i][0];
            long long dy = points[j][1] - points[i][1];
            if (dx == 0 && dy == 0) continue;

            long long g = __gcd(dx, dy);
            if (g != 0) {
                dx /= g;
                dy /= g;
            }
            if (dx < 0 || (dx == 0 && dy < 0)) {
                dx = -dx;
                dy = -dy;
            }
            slopeMap[{dx, dy}].insert({points[j][0], points[j][1]});
        }

        for (auto& entry : slopeMap) {
            int cnt = entry.second.size();
            if (cnt >= 3) {
                res += cnt * (cnt - 1) * (cnt - 2) / 6;
            }
        }
    }

    map<vector<long long>, long long> lineCount;
    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            long long x1 = points[i][0], y1 = points[i][1];
            long long x2 = points[j][0], y2 = points[j][1];

            long long A = y2 - y1;
            long long B = x1 - x2;
            long long C = x2 * y1 - x1 * y2;

            long long g = __gcd(__gcd(A, B), C);
            if (g != 0) {
                A /= g;
                B /= g;
                C /= g;
            }
            if (A < 0 || (A == 0 && B < 0)) {
                A = -A;
                B = -B;
                C = -C;
            }
            vector<long long> line = {A, B, C};
            lineCount[line]++;
        }
    }

    long long total = 0;
    for (auto& entry : lineCount) {
        long long cnt = entry.second;
        if (cnt >= 4) {
            total += cnt * (cnt - 1) * (cnt - 2) * (cnt - 3) / 24;
        }
    }

    res -= total * 4;

    return res;
}
